#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char A[100005], B[100005];
        scanf("%s",A);
        scanf("%s",B);
        int cntA=0,cntB=0;
        for(int i=0;i<N;i++) if(A[i]=='1') cntA++;
        for(int i=0;i<N;i++) if(B[i]=='1') cntB++;
        puts(cntA==cntB?"YES":"NO");
    }
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        string A,B; cin>>A>>B;
        int cntA=0,cntB=0;
        for(char c:A) if(c=='1') cntA++;
        for(char c:B) if(c=='1') cntB++;
        cout<<(cntA==cntB?"YES":"NO")<<'\n';
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            String A = br.readLine().trim();
            String B = br.readLine().trim();
            int cntA = 0, cntB = 0;
            for (int i = 0; i < N; i++) {
                if (A.charAt(i) == '1') cntA++;
                if (B.charAt(i) == '1') cntB++;
            }
            out.append(cntA == cntB ? "YES" : "NO").append('\n');
        }
        System.out.print(out.toString());
    }
}

